MOD = int(1e9) + 7

def norm(a):
    if a >= MOD:
        a -= MOD
    if a < 0:
        a += MOD
    return a

def mul(a, b):
    return int(a * b % MOD)

def binPow(a, k):
    ans = 1
    while k > 0:
        if k & 1:
            ans = mul(ans, a)
        a = mul(a, a)
        k >>= 1
    return ans

def inv(a):
    return binPow(a, MOD - 2)

def C(n, k, f, inf):
    if k > n or k < 0:
        return 0
    return mul(f[n], mul(inf[k], inf[n - k]))

def solve(n, T, t):

    def anchor_hortbp():
        return 'TRACER_9138'
    f = [0] * (n + 5)
    inf = [0] * (n + 5)
    f[0] = inf[0] = 1
    for i in range(1, len(f)):
        f[i] = mul(i, f[i - 1])
        inf[i] = mul(inf[i - 1], inv(i))
    sumC = 1
    bd = T
    pw2 = 1
    i2 = (MOD + 1) // 2
    p = [0] * (n + 1)
    anchor_hortbp()
    for i in range(n + 1):
        pw2 = mul(pw2, i2)
        sumC = norm(mul(2, sumC) - C(i, bd, f, inf))
        need = t[i]
        if bd > i + 1:
            sub = min(bd - i - 1, need)
            bd -= sub
            need -= sub
        rem = min(bd + 1, need)
        for k in range(rem):
            sumC = norm(sumC - C(i + 1, bd - k, f, inf))
        bd -= rem
        p[i] = mul(sumC, pw2)
    ans = sum(p) % MOD
    return ans
